import React, { useState } from 'react';

function Review({ review, onUpdate, onDelete }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedReview, setEditedReview] = useState({
    reviewer: review.reviewer,
    rating: review.rating,
    comment: review.comment
  });

  const handleDelete = () => {
    if (window.confirm('Are you sure you want to delete this review?')) {
      onDelete();
    }
  };

  const handleUpdate = (e) => {
    e.preventDefault();
    onUpdate(editedReview);
    setIsEditing(false);
  };

  const handleCancel = () => {
    setEditedReview({
      reviewer: review.reviewer,
      rating: review.rating,
      comment: review.comment
    });
    setIsEditing(false);
  };

  if (isEditing) {
    return (
      <div className="card border-primary animate-fade-in">
        <div className="card-body">
          <form onSubmit={handleUpdate} className="space-y-4">
            <div>
              <label className="form-label">Your Name</label>
              <input
                type="text"
                value={editedReview.reviewer}
                onChange={(e) => setEditedReview({...editedReview, reviewer: e.target.value})}
                className="form-input"
                required
              />
            </div>

            <div>
              <label className="form-label">Rating</label>
              <select
                value={editedReview.rating}
                onChange={(e) => setEditedReview({...editedReview, rating: parseInt(e.target.value)})}
                className="form-select"
                required
              >
                <option value={1}>1 Star - Poor</option>
                <option value={2}>2 Stars - Fair</option>
                <option value={3}>3 Stars - Good</option>
                <option value={4}>4 Stars - Very Good</option>
                <option value={5}>5 Stars - Excellent</option>
              </select>
            </div>

            <div>
              <label className="form-label">Your Review</label>
              <textarea
                value={editedReview.comment}
                onChange={(e) => setEditedReview({...editedReview, comment: e.target.value})}
                className="form-textarea"
                rows={4}
                placeholder="Share your thoughts about this book..."
                required
              />
            </div>

            <div className="flex gap-3">
              <button type="submit" className="btn btn-success flex-1">
                Update Review
              </button>
              <button type="button" onClick={handleCancel} className="btn btn-secondary flex-1">
                Cancel
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="card hover:shadow-md transition-all duration-300">
      <div className="card-body">
        <div className="flex items-start justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-primary rounded-full flex items-center justify-center shadow-sm">
              <span className="text-white font-bold text-lg">
                {review.reviewer.charAt(0).toUpperCase()}
              </span>
            </div>
            <div>
              <h4 className="font-bold text-primary text-lg">{review.reviewer}</h4>
              <p className="text-sm text-muted">{review.date}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setIsEditing(true)}
              className="p-2 text-muted hover:text-primary hover:bg-surface rounded-lg transition-all duration-200"
              title="Edit review"
            >
              <svg className="icon-sm" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
              </svg>
            </button>
            <button
              onClick={handleDelete}
              className="p-2 text-muted hover:text-danger hover:bg-surface rounded-lg transition-all duration-200"
              title="Delete review"
            >
              <svg className="icon-sm" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>
          </div>
        </div>

        <div className="flex items-center mb-4">
          <div className="flex items-center gap-1 mr-3">
            {[...Array(5)].map((_, i) => (
              <span 
                key={i} 
                className={`text-lg ${
                  i < review.rating ? 'text-warning' : 'text-muted'
                }`}
              >
                ★
              </span>
            ))}
          </div>
          <span className="text-lg font-bold text-primary">{review.rating}/5</span>
        </div>

        <p className="text-secondary leading-relaxed">{review.comment}</p>
      </div>
    </div>
  );
}

export default Review;
